// =============================================================
// Save Input Payload — audit per attempt (T-209)
// =============================================================
// Save resolved surveyLinkId BEFORE Supabase fetch.
// =============================================================

const https = require('https');

const SUPABASE_URL = $env.SUPABASE_URL;
if (!SUPABASE_URL) throw new Error('SUPABASE_URL environment variable not configured');
const SUPABASE_KEY = $env.SUPABASE_SERVICE_ROLE_KEY;

// @inline supabase-request
async function supabaseRequest(path, method, body) {
  const url = `${SUPABASE_URL}/rest/v1/${path}`;
  return new Promise((resolve, reject) => {
    const match = url.match(/^https?:\/\/([^/]+)(\/.*)$/);
    if (!match) { reject(new Error('Invalid SUPABASE_URL')); return; }
    const options = {
      hostname: match[1],
      path: match[2],
      method: method || 'GET',
      headers: {
        'apikey': SUPABASE_KEY,
        'Authorization': `Bearer ${SUPABASE_KEY}`,
        'Content-Type': 'application/json',
        'Prefer': 'return=representation',
      },
    };
    const req = https.request(options, (res) => {
      let data = '';
      res.on('data', (chunk) => data += chunk);
      res.on('end', () => {
        if (res.statusCode >= 400) {
          reject(new Error(`Supabase ${method || 'GET'} ${path} ${res.statusCode}: ${data}`));
          return;
        }
        try {
          resolve(data ? JSON.parse(data) : null);
        } catch (e) {
          reject(new Error(`Parse error for ${path}: ${data}`));
        }
      });
    });
    req.on('error', reject);
    if (body !== undefined && body !== null) req.write(JSON.stringify(body));
    req.end();
  });
}
// @end-inline supabase-request

const item = $input.first().json;
const { resolvedConfig, variableContext, tenantId } = item;
const surveyLinkId = (resolvedConfig && resolvedConfig.surveyLinkIdExpression) ?? (variableContext && variableContext.surveyLinkId) ?? null;
const inputPayload = {
  surveyLinkId,
  tenant_id: tenantId,
};

if (item.currentStepExecId) {
  await supabaseRequest(
    `workflow_step_executions?id=eq.${item.currentStepExecId}`,
    'PATCH',
    { input_payload: inputPayload }
  );
}

return { json: item };

// =============================================================
// Get Survey Link Handler — fetch survey link data
// =============================================================
// Reads variableContext.surveyLinkId (trigger-level flat key),
// fetches survey_links row joined to surveys, returns:
//   notificationEmail, token, surveyTitle
// tenant_id filter on survey_links fetch for security.
// =============================================================

const https = require('https');

const SUPABASE_URL = $env.SUPABASE_URL;
if (!SUPABASE_URL) throw new Error('SUPABASE_URL not configured');
const SUPABASE_KEY = $env.SUPABASE_SERVICE_ROLE_KEY;

// @inline supabase-request
async function supabaseRequest(path, method, body) {
  const url = `${SUPABASE_URL}/rest/v1/${path}`;
  return new Promise((resolve, reject) => {
    const match = url.match(/^https?:\/\/([^/]+)(\/.*)$/);
    if (!match) { reject(new Error('Invalid SUPABASE_URL')); return; }
    const options = {
      hostname: match[1],
      path: match[2],
      method: method || 'GET',
      headers: {
        'apikey': SUPABASE_KEY,
        'Authorization': `Bearer ${SUPABASE_KEY}`,
        'Content-Type': 'application/json',
        'Prefer': 'return=representation',
      },
    };
    const req = https.request(options, (res) => {
      let data = '';
      res.on('data', (chunk) => data += chunk);
      res.on('end', () => {
        if (res.statusCode >= 400) {
          reject(new Error(`Supabase ${method || 'GET'} ${path} ${res.statusCode}: ${data}`));
          return;
        }
        try {
          resolve(data ? JSON.parse(data) : null);
        } catch (e) {
          reject(new Error(`Parse error for ${path}: ${data}`));
        }
      });
    });
    req.on('error', reject);
    if (body !== undefined && body !== null) req.write(JSON.stringify(body));
    req.end();
  });
}
// @end-inline supabase-request

try {
  const item = $input.first().json;
  const { resolvedConfig, variableContext, tenantId } = item;

  // surveyLinkIdExpression is pre-resolved by Prepare Current Step — use it directly.
  // Falls back to trigger-level variableContext.surveyLinkId for backward compat.
  const surveyLinkId = resolvedConfig?.surveyLinkIdExpression ?? variableContext.surveyLinkId;
  if (!surveyLinkId) throw new Error('get_survey_link: surveyLinkId not found in resolvedConfig or variableContext');

  const safeTenantId = tenantId ?? '00000000-0000-0000-0000-000000000000';

  // Fetch survey_link row with tenant_id security filter
  // Join surveys to get title
  // survey_links has no tenant_id column — must verify tenant via survey_link.survey_id → surveys.tenant_id.
  // Accept either survey_links.id OR survey_links.token as the lookup key (defensive — older trigger
  // payloads may pass the token; current code passes the id). Try id first, then fall back to token.
  let surveyLinks = await supabaseRequest(
    `survey_links?id=eq.${surveyLinkId}&limit=1`
  );
  if (!surveyLinks.length) {
    surveyLinks = await supabaseRequest(
      `survey_links?token=eq.${surveyLinkId}&limit=1`
    );
  }
  if (!surveyLinks.length) {
    throw new Error(`Survey link ${surveyLinkId} not found by id or token`);
  }
  const surveyLink = surveyLinks[0];
  if (!surveyLink.survey_id) {
    throw new Error(`Survey link ${surveyLinkId} has no survey_id`);
  }
  // Fetch parent survey to verify tenant + get title
  const surveys = await supabaseRequest(
    `surveys?id=eq.${surveyLink.survey_id}&tenant_id=eq.${safeTenantId}&limit=1`
  );
  if (!surveys.length) {
    throw new Error(`Survey link ${surveyLinkId} does not belong to tenant ${safeTenantId}`);
  }
  surveyLink.surveys = surveys[0];

  // surveys.title comes from the inner-join in the survey_links query above
  const surveyTitle = surveyLink.surveys?.title ?? '';

  return {
    json: {
      ...item,
      stepResult: {
        success: true,
        outputPayload: {
          notificationEmail: surveyLink.notification_email ?? null,
          token: surveyLink.token ?? null,
          surveyTitle,
        },
      },
    }
  };
} catch (err) {
  const item = $input.first().json;
  return { json: { ...item, stepResult: { success: false, error: err.message } } };
}
